import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';

const initialTasks = {
  toilettes: {
    title: 'Toilettes',
    points: [
      { id: 't1', name: 'Cuvette' },
      { id: 't2', name: 'Sol' },
      { id: 't3', name: 'Surfaces' },
      { id: 't4', name: 'Poignée' },
    ],
    refills: [
      { id: 'tr1', name: 'Savon' },
      { id: 'tr2', name: 'Papier' },
      { id: 'tr3', name: 'PQ' },
      { id: 'tr4', name: 'Serviette hygiénique' },
    ],
  },
  barCuisine: {
    title: 'Bar & Cuisine',
    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)' },
      { id: 'bc2', name: 'Murs (1/mois)' },
      { id: 'bc3', name: "Système d'aspiration (1/an)" },
    ],
  },
};

// Component to render a single checklist item
function ChecklistItem({ item, onToggle, log }) {
  const isDone = log && log.done;
  return (
    <div className={`flex items-center justify-between p-2 rounded-lg ${isDone ? 'bg-green-900' : 'bg-gray-700'}`}>
      <span>{item.name}</span>
      <div className="flex items-center gap-4">
        {isDone && (
          <div className="text-xs text-gray-400 text-right">
            Fait par {log.user}
            <br />
            {new Date(log.timestamp).toLocaleString('fr-FR')}
          </div>
        )}
        <button
          onClick={() => onToggle(item.id)}
          className={`px-4 py-2 rounded w-28 ${isDone ? 'bg-yellow-600 hover:bg-yellow-700' : 'bg-green-600 hover:bg-green-700'}`}
        >
          {isDone ? 'Annuler' : 'Valider'}
        </button>
      </div>
    </div>
  );
}

export default function CleaningChecklist() {
  const { user } = useAuth(); // Get current user
  const [logs, setLogs] = useState({}); // Example: { t1: { done: true, user: '...', timestamp: ... } }

  const handleToggle = (itemId) => {
    setLogs(prevLogs => {
      const existingLog = prevLogs[itemId];
      if (existingLog) {
        // Toggle off: remove the log
        const newLogs = { ...prevLogs };
        delete newLogs[itemId];
        return newLogs;
      } else {
        // Toggle on: add a new log
        return {
          ...prevLogs,
          [itemId]: {
            done: true,
            user: user?.email || 'Utilisateur inconnu',
            timestamp: new Date().toISOString(),
          }
        };
      }
    });
  };

  return (
    <div className="p-4 sm:p-6 text-white max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-yellow-500 mb-6 text-center">Checklist de Nettoyage</h1>
      {Object.values(initialTasks).map(category => (
        <div key={category.title} className="mb-8">
          <h2 className="text-2xl font-semibold border-b-2 border-gray-600 pb-2 mb-4">{category.title}</h2>
          <div className="space-y-3">
            {category.points && category.points.map(item => (
              <ChecklistItem key={item.id} item={item} onToggle={handleToggle} log={logs[item.id]} />
            ))}
            {category.refills && category.refills.map(item => (
              <ChecklistItem key={item.id} item={item} onToggle={handleToggle} log={logs[item.id]} />
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

