    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)' },
      { id: 'bc2', name: 'Murs (1/mois)' },
      { id: 'bc3', name: "Système d'aspiration (1/an)" },
    ],
  },
};

// Component to render a single checklist item
function ChecklistItem({ item, onToggle, log }) {
  const isDone = log && log.done;
  // Firestore timestamp needs to be converted to a Date object
  const displayTimestamp = log?.timestamp?.toDate ? log.timestamp.toDate() : new Date(log.timestamp);

  return (
    <div className={`flex items-center justify-between p-2 rounded-lg ${isDone ? 'bg-green-900' : 'bg-gray-700'}`}>
      <span>{item.name}</span>
      <div className="flex items-center gap-4">
        {isDone && (
          <div className="text-xs text-gray-400 text-right">
            Fait par {log.user}
            <br />
            {displayTimestamp.toLocaleString('fr-FR')}
          </div>
        )}
        <button
          onClick={() => onToggle(item.id, log?.firestoreId)}
          className={`px-4 py-2 rounded w-28 ${isDone ? 'bg-yellow-600 hover:bg-yellow-700' : 'bg-green-600 hover:bg-green-700'}`}
        >
          {isDone ? 'Annuler' : 'Valider'}
        </button>
      </div>
    </div>
  );
}

export default function CleaningChecklist() {
  const { user } = useAuth();
  const [logs, setLogs] = useState({});
  const logsCollectionRef = collection(db, 'cleaning_logs');

  useEffect(() => {
    // Set up a real-time listener for today's logs
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const startOfToday = Timestamp.fromDate(today);

    const q = query(logsCollectionRef, where('timestamp', '>=', startOfToday));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const dailyLogs = {};
      querySnapshot.forEach((doc) => {
        const data = doc.data();
        dailyLogs[data.taskId] = {
          firestoreId: doc.id,
          done: true,
          user: data.userEmail,
          timestamp: data.timestamp,
        };
      });
      setLogs(dailyLogs);
    });

    // Cleanup listener on unmount
    return () => unsubscribe();
  }, []); // Empty dependency array ensures this runs only once on mount

  const handleToggle = async (itemId, firestoreId) => {
    if (!user) {
      console.error("User not authenticated");
      return; // Prevent action if user is not logged in
    }

    if (firestoreId) {
      // Task is already done, so we are toggling off (annuler)
      const docRef = doc(db, 'cleaning_logs', firestoreId);
      await deleteDoc(docRef);
    } else {
      // Task is not done, so we are toggling on (valider)
      await addDoc(logsCollectionRef, {
        taskId: itemId,
        userId: user.uid,
        userEmail: user.email || 'Utilisateur inconnu',
        timestamp: Timestamp.now(),
      });
    }
  };

  return (
    <div className="p-4 sm:p-6 text-white max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-yellow-500 mb-6 text-center">Checklist de Nettoyage</h1>
      {Object.values(initialTasks).map(category => (
        <div key={category.title} className="mb-8">
          <h2 className="text-2xl font-semibold border-b-2 border-gray-600 pb-2 mb-4">{category.title}</h2>
          <div className="space-y-3">
            {category.points && category.points.map(item => (
              <ChecklistItem key={item.id} item={item} onToggle={handleToggle} log={logs[item.id]} />
            ))}
            {category.refills && category.refills.map(item => (
              <ChecklistItem key={item.id} item={item} onToggle={handleToggle} log={logs[item.id]} />
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

