import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { db } from '../firebase/config';
import {
  collection,
  query,
  where,
  onSnapshot,
  addDoc,
  Timestamp,
  orderBy,
} from 'firebase/firestore';
import HistoryModal from './HistoryModal'; // Import the new modal component
import { History } from 'lucide-react'; // Import an icon for the history button

const initialTasks = {
  toilettes: {
    title: 'Toilettes',
    points: [
      { id: 't1', name: 'Cuvette' },
      { id: 't2', name: 'Sol' },
      { id: 't3', name: 'Surfaces' },
      { id: 't4', name: 'Poignée' },
    ],
    refills: [
      { id: 'tr1', name: 'Savon' },
      { id: 'tr2', name: 'Papier' },
      { id: 'tr3', name: 'PQ' },
      { id: 'tr4', name: 'Serviette hygiénique' },
    ],
  },
  barCuisine: {
    title: 'Bar & Cuisine',
    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)' },
      { id: 'bc2', name: 'Murs (1/mois)' },
      { id: 'bc3', name: "Système d'aspiration (1/an)" },
    ],
  },
};

// --- ChecklistItem Component ---
function ChecklistItem({ item, onLogEvent, onShowHistory, log }) {
  const isDone = log && log.action === 'done';
  const displayTimestamp = log?.timestamp?.toDate ? log.timestamp.toDate() : null;

  return (
    <div className={`flex items-center justify-between p-2 rounded-lg ${isDone ? 'bg-green-900' : 'bg-gray-700'}`}>
      <span>{item.name}</span>
      <div className="flex items-center gap-2">
        {isDone && displayTimestamp && (
          <div className="text-xs text-gray-400 text-right">
            Fait par {log.userEmail}
            <br />
            {displayTimestamp.toLocaleString('fr-FR')}
          </div>
        )}
        <button
          onClick={() => onShowHistory(item)}
          className="p-2 text-gray-400 hover:text-white"
          title="Voir l'historique"
        >
          <History size={18} />
        </button>
        <button
          onClick={() => onLogEvent(item.id, isDone)}
          className={`px-4 py-2 rounded w-28 ${isDone ? 'bg-yellow-600 hover:bg-yellow-700' : 'bg-green-600 hover:bg-green-700'}`}
        >
          {isDone ? 'Annuler' : 'Valider'}
        </button>
      </div>
    </div>
  );
}

// --- Main CleaningChecklist Component ---
export default function CleaningChecklist() {
  const { user } = useAuth();
  const [currentStatus, setCurrentStatus] = useState({});
  const [modalTask, setModalTask] = useState(null); // To control the history modal
  const historyCollectionRef = collection(db, 'cleaning_history');

  useEffect(() => {
    // Listener for all history events to determine the CURRENT status
    const q = query(historyCollectionRef, orderBy('timestamp', 'asc'));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const statusMap = new Map();
      querySnapshot.forEach((doc) => {
        const event = doc.data();
        // The last event for a given taskId determines its current status
        statusMap.set(event.taskId, event);
      });

      const latestStatuses = Object.fromEntries(statusMap.entries());
      setCurrentStatus(latestStatuses);
    });

    return () => unsubscribe();
  }, []);

  const handleLogEvent = async (itemId, isCurrentlyDone) => {
    if (!user) {
      console.error("User not authenticated");
      return;
    }

    const newAction = isCurrentlyDone ? 'undone' : 'done';

    await addDoc(historyCollectionRef, {
      taskId: itemId,
      action: newAction,
      userId: user.uid,
      userEmail: user.email || 'Utilisateur inconnu',
      timestamp: Timestamp.now(),
    });
  };

  const handleShowHistory = (task) => {
    setModalTask(task);
  };

  const handleCloseModal = () => {
    setModalTask(null);
  };

  return (
    <div className="p-4 sm:p-6 text-white max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-yellow-500 mb-6 text-center">Checklist de Nettoyage</h1>

      {Object.values(initialTasks).map(category => (
        <div key={category.title} className="mb-8">
          <h2 className="text-2xl font-semibold border-b-2 border-gray-600 pb-2 mb-4">{category.title}</h2>
          <div className="space-y-3">
            {category.points && category.points.map(item => (
              <ChecklistItem 
                key={item.id} 
                item={item} 
                onLogEvent={handleLogEvent}
                onShowHistory={handleShowHistory}
                log={currentStatus[item.id]} 
              />
            ))}
            {category.refills && category.refills.map(item => (
              <ChecklistItem 
                key={item.id} 
                item={item} 
                onLogEvent={handleLogEvent}
                onShowHistory={handleShowHistory}
                log={currentStatus[item.id]} 
              />
            ))}
          </div>
        </div>
      ))}

      {modalTask && (
        <HistoryModal 
          taskId={modalTask.id} 
          taskName={modalTask.name} 
          onClose={handleCloseModal} 
        />
      )}
    </div>
  );
}

