  Timestamp,
  orderBy,
} from 'firebase/firestore';
import HistoryModal from './HistoryModal';
import { History } from 'lucide-react';

const TEST_FREQUENCY = 5000; // 5 seconds for testing

const initialTasks = {
  toilettes: {
    title: 'Toilettes',
    points: [
      { id: 't1', name: 'Cuvette', frequency: TEST_FREQUENCY },
      { id: 't2', name: 'Sol', frequency: TEST_FREQUENCY },
      { id: 't3', name: 'Surfaces', frequency: TEST_FREQUENCY },
      { id: 't4', name: 'Poignée', frequency: TEST_FREQUENCY },
    ],
    refills: [
      { id: 'tr1', name: 'Savon', frequency: TEST_FREQUENCY },
      { id: 'tr2', name: 'Papier', frequency: TEST_FREQUENCY },
      { id: 'tr3', name: 'PQ', frequency: TEST_FREQUENCY },
      { id: 'tr4', name: 'Serviette hygiénique', frequency: TEST_FREQUENCY },
    ],
  },
  barCuisine: {
    title: 'Bar & Cuisine',
    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)', frequency: TEST_FREQUENCY },
      { id: 'bc2', name: 'Murs (1/mois)', frequency: TEST_FREQUENCY },
      { id: 'bc3', name: "Système d'aspiration (1/an)", frequency: TEST_FREQUENCY },
    ],
  },
};

// --- ChecklistItem Component ---
function ChecklistItem({ item, onLogEvent, onShowHistory, isDone, log }) {
  const displayTimestamp = isDone && log?.timestamp?.toDate ? log.timestamp.toDate() : null;

  return (
    <div className={`flex items-center justify-between p-2 rounded-lg transition-colors duration-300 ${isDone ? 'bg-green-900' : 'bg-gray-700'}`}>
      <span>{item.name}</span>
      <div className="flex items-center gap-2">
        {isDone && displayTimestamp && (
          <div className="text-xs text-gray-400 text-right">
            Fait par {log.userEmail}
            <br />
            {displayTimestamp.toLocaleString('fr-FR')}
          </div>
        )}
        <button
          onClick={() => onShowHistory(item)}
          className="p-2 text-gray-400 hover:text-white"
          title="Voir l'historique"
        >
          <History size={18} />
        </button>
        <button
          onClick={() => onLogEvent(item.id, isDone)}
          className={`px-4 py-2 rounded w-28 ${isDone ? 'bg-green-600 hover:bg-green-700' : 'bg-yellow-600 hover:bg-yellow-700'}`}
        >
          {isDone ? 'Fait' : 'À faire'}
        </button>
      </div>
    </div>
  );
}

// --- Main CleaningChecklist Component ---
export default function CleaningChecklist() {
  const { user } = useAuth();
  const [lastEvents, setLastEvents] = useState({});
  const [modalTask, setModalTask] = useState(null);
  const [now, setNow] = useState(Date.now());
  const historyCollectionRef = collection(db, 'cleaning_history');

  // Set up a timer to re-render the component every second
  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Set up a listener for all history events to determine the CURRENT status
  useEffect(() => {
    const q = query(historyCollectionRef, orderBy('timestamp', 'asc'));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const eventMap = new Map();
      querySnapshot.forEach((doc) => {
        const event = doc.data();
        eventMap.set(event.taskId, event);
      });

      const latestEvents = Object.fromEntries(eventMap.entries());
      setLastEvents(latestEvents);
    });

    return () => unsubscribe();
  }, []);

  const handleLogEvent = async (itemId, isCurrentlyDone) => {
    if (!user) {
      console.error("User not authenticated");
      return;
    }
    // We always log the 'done' action. The status automatically reverts to 'À faire' after the frequency timeout.
    // If the user clicks 'À faire', it means they are marking it as 'done' again.
    await addDoc(historyCollectionRef, {
      taskId: itemId,
      action: 'done', // We only ever log 'done' actions now
      userId: user.uid,
      userEmail: user.email || 'Utilisateur inconnu',
      timestamp: Timestamp.now(),
    });
  };

  const handleShowHistory = (task) => setModalTask(task);
  const handleCloseModal = () => setModalTask(null);

  return (
    <div className="p-4 sm:p-6 text-white max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-yellow-500 mb-6 text-center">Checklist de Nettoyage</h1>

      {Object.values(initialTasks).map(category => (
        <div key={category.title} className="mb-8">
          <h2 className="text-2xl font-semibold border-b-2 border-gray-600 pb-2 mb-4">{category.title}</h2>
          <div className="space-y-3">
            {[...category.points, ...(category.refills || [])].map(item => {
              const lastEvent = lastEvents[item.id];
              let isDone = false;
              if (lastEvent && lastEvent.action === 'done') {
                const lastDoneTime = lastEvent.timestamp.toDate().getTime();
                if ((now - lastDoneTime) < item.frequency) {
                  isDone = true;
                }
              }
              return (
                <ChecklistItem 
                  key={item.id} 
                  item={item} 
                  onLogEvent={handleLogEvent}
                  onShowHistory={handleShowHistory}
                  isDone={isDone}
                  log={isDone ? lastEvent : null} 
                />
              );
            })}
          </div>
        </div>
      ))}

      {modalTask && (
        <HistoryModal 
          taskId={modalTask.id} 
          taskName={modalTask.name} 
          onClose={handleCloseModal} 
        />
      )}
    </div>
  );
}

