import React, { useState, useEffect } from 'react';
import { Settings, RefreshCw, Trash2, CheckCheck } from 'lucide-react';
import { resetDatabase, emptyDatabase } from '../firebase/dbActions';
import Card from './Card';
import { db } from '../firebase/config';
import { collection, getDocs, writeBatch, doc, onSnapshot, updateDoc } from 'firebase/firestore';

// This is a temporary copy of the initial tasks for the one-time migration.
const initialTasksForMigration = {
  toilettes: {
    title: 'Toilettes',
    points: [
      { id: 't1', name: 'Cuvette', frequency: 3600000 * 2 }, // 2 hours
      { id: 't2', name: 'Sol', frequency: 3600000 * 4 }, // 4 hours
      { id: 't3', name: 'Surfaces', frequency: 3600000 * 2 }, // 2 hours
      { id: 't4', name: 'Poignée', frequency: 3600000 }, // 1 hour
    ],
    refills: [
      { id: 'tr1', name: 'Savon', frequency: 86400000 }, // 24 hours
      { id: 'tr2', name: 'Papier', frequency: 86400000 }, // 24 hours
      { id: 'tr3', name: 'PQ', frequency: 86400000 }, // 24 hours
      { id: 'tr4', name: 'Serviette hygiénique', frequency: 86400000 }, // 24 hours
    ],
  },
  barCuisine: {
    title: 'Bar & Cuisine',
    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)', frequency: 604800000 }, // 7 days
      { id: 'bc2', name: 'Murs (1/mois)', frequency: 2592000000 }, // 30 days
      { id: 'bc3', name: "Système d'aspiration (1/an)", frequency: 31536000000 }, // 365 days
    ],
  },
};

export default function AdminPanel() {
  const [tableCount, setTableCount] = useState(4);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isEmptying, setIsEmptying] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const [cleaningTasks, setCleaningTasks] = useState([]);
  const [isSaving, setIsSaving] = useState(false);

  // --- System Config Logic ---
  // ... (handleReset, handleEmpty functions are unchanged)

  // --- Cleaning Task Logic ---
  useEffect(() => {
    const tasksCollectionRef = collection(db, 'cleaning_tasks');
    const unsubscribe = onSnapshot(tasksCollectionRef, (snapshot) => {
      const tasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      tasks.sort((a, b) => a.name.localeCompare(b.name)); // Sort alphabetically
      setCleaningTasks(tasks);
    });
    return () => unsubscribe();
  }, []);

  const handleFrequencyChange = (id, value) => {
    const newTasks = cleaningTasks.map(task => 
      task.id === id ? { ...task, frequency: value * 60000 } : task // Convert minutes to ms
    );
    setCleaningTasks(newTasks);
  };

  const handleSaveChanges = async () => {
    setIsSaving(true);
    try {
      const batch = writeBatch(db);
      cleaningTasks.forEach(task => {
        const docRef = doc(db, 'cleaning_tasks', task.id);
        batch.update(docRef, { frequency: task.frequency });
      });
      await batch.commit();
      alert("Fréquences sauvegardées avec succès !");
    } catch (error) {
      console.error("Erreur lors de la sauvegarde :", error);
      alert("Erreur lors de la sauvegarde des fréquences.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleInitCleaningTasks = async () => { /* ... unchanged ... */ };

  return (
    <>
      <Card title="Configuration Système" titleIcon={<Settings />}>
        {/* ... unchanged system config JSX ... */}
      </Card>

      <Card title="Configuration Tâches de Nettoyage" titleIcon={<CheckCheck />}>
        <div className="space-y-4">
          <div className="flex items-end gap-4">
            <button 
              onClick={handleInitCleaningTasks}
              disabled={isInitializing}
              className="bg-blue-600/20 text-blue-300 rounded-lg border border-blue-800 hover:text-white transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
            >
              <RefreshCw className={`w-3 h-3 ${isInitializing ? 'animate-spin' : ''}`} />
              {isInitializing ? 'Initialisation...' : 'Initialiser Tâches'}
            </button>
            <p className="text-[10px] text-gray-500 italic">
              Action unique pour créer la configuration de base dans la DB.
            </p>
          </div>

          <div className="max-h-60 overflow-y-auto space-y-2 pr-2">
            {cleaningTasks.map(task => (
              <div key={task.id} className="flex items-center justify-between gap-4">
                <label className="text-sm text-gray-300 flex-1">{task.name}</label>
                <div className="flex items-center gap-2">
                  <input
                    type="number"
                    value={Math.round(task.frequency / 60000)} // Display in minutes
                    onChange={(e) => handleFrequencyChange(task.id, e.target.value)}
                    className="w-24 bg-black border border-gray-800 rounded p-1 text-white outline-none focus:border-mictlan-gold"
                    min="1"
                  />
                  <span className="text-xs text-gray-500">min</span>
                </div>
              </div>
            ))}
          </div>

          {cleaningTasks.length > 0 && (
            <div className="flex justify-end">
              <button
                onClick={handleSaveChanges}
                disabled={isSaving}
                className="bg-green-600/80 text-white rounded-lg hover:bg-green-500 transition-all px-4 py-2 font-bold text-sm flex items-center gap-2"
              >
                {isSaving ? 'Sauvegarde...' : 'Sauvegarder les Fréquences'}
              </button>
            </div>
          )}
        </div>
      </Card>
    </>
  );
}

