import { useState } from 'react';
import { Settings, RefreshCw, Trash2, CheckCheck } from 'lucide-react';
import { resetDatabase, emptyDatabase } from '../firebase/dbActions';
import Card from './Card';
import { db } from '../firebase/config';
import { collection, getDocs, writeBatch, doc } from 'firebase/firestore';

// This is a temporary copy of the initial tasks for the one-time migration.
const initialTasksForMigration = {
  toilettes: {
    title: 'Toilettes',
    points: [
      { id: 't1', name: 'Cuvette', frequency: 3600000 * 2 }, // 2 hours
      { id: 't2', name: 'Sol', frequency: 3600000 * 4 }, // 4 hours
      { id: 't3', name: 'Surfaces', frequency: 3600000 * 2 }, // 2 hours
      { id: 't4', name: 'Poignée', frequency: 3600000 }, // 1 hour
    ],
    refills: [
      { id: 'tr1', name: 'Savon', frequency: 86400000 }, // 24 hours
      { id: 'tr2', name: 'Papier', frequency: 86400000 }, // 24 hours
      { id: 'tr3', name: 'PQ', frequency: 86400000 }, // 24 hours
      { id: 'tr4', name: 'Serviette hygiénique', frequency: 86400000 }, // 24 hours
    ],
  },
  barCuisine: {
    title: 'Bar & Cuisine',
    points: [
      { id: 'bc1', name: 'Grille de la hotte (1/semaine)', frequency: 604800000 }, // 7 days
      { id: 'bc2', name: 'Murs (1/mois)', frequency: 2592000000 }, // 30 days
      { id: 'bc3', name: "Système d'aspiration (1/an)", frequency: 31536000000 }, // 365 days
    ],
  },
};

export default function AdminPanel() {
  const [tableCount, setTableCount] = useState(4);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isEmptying, setIsEmptying] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const handleReset = async () => {
    setIsUpdating(true);
    try {
      await resetDatabase(tableCount);
      alert("Tables réinitialisées avec succès.");
    } catch(err) {
      console.error(err);
      alert("Erreur lors de la mise à jour des tables.");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleEmpty = async () => {
    if (!confirm("Êtes-vous sûr de vouloir vider les collections principales (tables, inventory, logs) ? Cette action est irréversible.")) {
      return;
    }
    setIsEmptying(true);
    try {
      await emptyDatabase();
      alert("Collections vidées avec succès.");
    } catch(err) {
      console.error(err);
      alert("Erreur lors du vidage des collections.");
    }
    finally {
      setIsEmptying(false);
    }
  };

  const handleInitCleaningTasks = async () => {
    if (!confirm("Voulez-vous initialiser la configuration des tâches de nettoyage dans la DB ? (Action unique)")) {
      return;
    }
    setIsInitializing(true);
    try {
      const tasksCollectionRef = collection(db, 'cleaning_tasks');
      const snapshot = await getDocs(tasksCollectionRef);
      if (!snapshot.empty) {
        alert("Les tâches de nettoyage sont déjà initialisées.");
        setIsInitializing(false);
        return;
      }

      const batch = writeBatch(db);
      Object.values(initialTasksForMigration).forEach(category => {
        const allTasks = [...(category.points || []), ...(category.refills || [])];
        allTasks.forEach(task => {
          const docRef = doc(tasksCollectionRef, task.id);
          batch.set(docRef, { ...task, category: category.title });
        });
      });

      await batch.commit();
      alert("Configuration des tâches de nettoyage initialisée avec succès !");

    } catch (error) {
      console.error("Erreur lors de l'initialisation des tâches :", error);
      alert("Erreur lors de l'initialisation des tâches.");
    } finally {
      setIsInitializing(false);
    }
  };

  return (
    <>
      <Card title="Configuration Système" titleIcon={<Settings />}>
        <div className="flex items-end gap-4 mb-4">
          <div className="flex-1">
            <label className="block text-gray-500 text-[9px] uppercase mb-1">Nombre de tables en salle</label>
            <input 
              type="number" 
              value={tableCount}
              onChange={(e) => setTableCount(e.target.value)}
              className="w-full bg-black border border-gray-800 rounded p-2 text-white outline-none focus:border-mictlan-gold"
              min="1"
              max="50"
            />
          </div>
          <button 
            onClick={handleReset}
            disabled={isUpdating}
            className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
          >
            <RefreshCw className={`w-3 h-3 ${isUpdating ? 'animate-spin' : ''}`} />
            {isUpdating ? 'Mise à jour...' : 'Réinitialiser Salle'}
          </button>
          <button 
            onClick={handleEmpty}
            disabled={isEmptying}
            className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
          >
            <Trash2 className={`w-3 h-3 ${isEmptying ? 'animate-spin' : ''}`} />
            {isEmptying ? 'Vidage...' : 'Vider DB'}
          </button>
        </div>
        <p className="text-[8px] text-gray-600 mt-2 italic font-mono uppercase">
          * Réinitialiser Salle génère {tableCount} tables. Vider DB supprime les données des tables, inventaire et logs.
        </p>
      </Card>
      <Card title="Configuration Tâches de Nettoyage" titleIcon={<CheckCheck />}>
        <div className="flex items-end gap-4">
          <button 
            onClick={handleInitCleaningTasks}
            disabled={isInitializing}
            className="bg-blue-600/20 text-blue-300 rounded-lg border border-blue-800 hover:text-white transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
          >
            <RefreshCw className={`w-3 h-3 ${isInitializing ? 'animate-spin' : ''}`} />
            {isInitializing ? 'Initialisation...' : 'Initialiser Tâches Nettoyage'}
          </button>
          <p className="text-[10px] text-gray-500 italic">
            Cliquez pour enregistrer la configuration de base des tâches dans la DB (action unique).
          </p>
        </div>
      </Card>
    </>
  );
}

