// --- ChecklistItem Component ---
function ChecklistItem({ item, onLogEvent, onShowHistory, isDone, log, isAdmin, onFrequencyChange }) {
  const displayTimestamp = isDone && log?.timestamp?.toDate ? log.timestamp.toDate() : null;
  const [editingFrequency, setEditingFrequency] = useState(false);
  const [newFrequencyMinutes, setNewFrequencyMinutes] = useState(Math.round(item.frequency / 60000));

  useEffect(() => {
    setNewFrequencyMinutes(Math.round(item.frequency / 60000));
  }, [item.frequency]);

  const handleFrequencySave = () => {
    onFrequencyChange(item.id, newFrequencyMinutes);
    setEditingFrequency(false);
  };

  return (
    <div className={`flex items-center justify-between p-2 rounded-lg transition-colors duration-300 ${isDone ? 'bg-green-900' : 'bg-gray-700'}`}>
      <span className="flex-1 mr-2">{item.name}</span>

      <div className="flex items-center gap-2">
        {isAdmin && !editingFrequency && (
          <span className="text-sm text-gray-400 cursor-pointer" onClick={() => setEditingFrequency(true)} title="Modifier la fréquence">
            ({Math.round(item.frequency / 60000)} min)
          </span>
        )}
        {isAdmin && editingFrequency && (
          <div className="flex items-center gap-1">
            <input
              type="number"
              value={newFrequencyMinutes}
              onChange={(e) => setNewFrequencyMinutes(parseInt(e.target.value) || 0)}
              className="w-16 bg-black border border-gray-800 rounded p-1 text-white text-xs outline-none focus:border-mictlan-gold"
              min="1"
            />
            <span className="text-xs text-gray-500">min</span>
            <button onClick={handleFrequencySave} className="bg-blue-600 px-2 py-1 text-xs rounded hover:bg-blue-500">
              OK
            </button>
            <button onClick={() => setEditingFrequency(false)} className="bg-gray-500 px-2 py-1 text-xs rounded hover:bg-gray-400">
              X
            </button>
          </div>
        )}
        {!isAdmin && (
          <span className="text-sm text-gray-400">({Math.round(item.frequency / 60000)} min)</span>
        )}

        {isDone && displayTimestamp && (
          <div className="text-xs text-gray-400 text-right min-w-[120px]">
            Fait par {log.userEmail}
            <br />
            {displayTimestamp.toLocaleString('fr-FR')}
          </div>
        )}
        <button
          onClick={() => onShowHistory(item)}
          className="p-2 text-gray-400 hover:text-white"
          title="Voir l'historique"
        >
          <History size={18} />
        </button>
        <button
          onClick={() => onLogEvent(item.id)}
          className={`px-4 py-2 rounded w-28 ${isDone ? 'bg-green-600 hover:bg-green-700' : 'bg-yellow-600 hover:bg-yellow-700'}`}
        >
          {isDone ? 'Fait' : 'À faire'}
        </button>
      </div>
    </div>
  );
}

// --- Main CleaningChecklist Component ---
export default function CleaningChecklist() {
  const { user, userData } = useAuth(); // Get isAdmin status
  const isAdmin = userData?.role === 'admin';
  const [taskConfig, setTaskConfig] = useState({}); // Holds the task configuration from Firestore
  const [lastEvents, setLastEvents] = useState({});
  const [modalTask, setModalTask] = useState(null);
  const [now, setNow] = useState(Date.now());

  // States for adding new item
  const [showAddItemForm, setShowAddItemForm] = useState(false);
  const [newItemName, setNewItemName] = useState('');
  const [newItemFrequencyMinutes, setNewItemFrequencyMinutes] = useState(60); // Default 60 minutes
  const [newItemCategory, setNewItemCategory] = useState('');
  const [isAddingItem, setIsAddingItem] = useState(false); // Loading state for add item

  // Set up a timer to re-render the component every second
  useEffect(() => {
    const timer = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, []);

  // One-time seeding of cleaning_tasks if the collection is empty
  useEffect(() => {
    const seedTasks = async () => {
      const tasksCollectionRef = collection(db, 'cleaning_tasks');
      const snapshot = await getDocs(tasksCollectionRef);
      if (snapshot.empty) {
        const batch = writeBatch(db);
        Object.values(initialTasksForSeeding).forEach(category => {
          const allTasks = [...(category.points || []), ...(category.refills || [])];
          allTasks.forEach(task => {
            const docRef = firestoreDoc(tasksCollectionRef, task.id);
            batch.set(docRef, { ...task, category: category.title });
          });
        });
        await batch.commit();
        console.log("Cleaning tasks seeded successfully!");
      }
    };
    seedTasks();
  }, []); // Run once on mount

  // Fetch task configuration from Firestore
  useEffect(() => {
    const tasksCollectionRef = collection(db, 'cleaning_tasks');
    const unsubscribe = onSnapshot(tasksCollectionRef, (snapshot) => {
      const groupedTasks = {};
      snapshot.forEach(doc => {
        const task = doc.data();
        if (!groupedTasks[task.category]) {
          groupedTasks[task.category] = [];
        }
        groupedTasks[task.category].push(task);
      });
      // Sort tasks within each category by name
      Object.keys(groupedTasks).forEach(category => {
        groupedTasks[category].sort((a, b) => a.name.localeCompare(b.name));
      });
      setTaskConfig(groupedTasks);
    });
    return () => unsubscribe();
  }, []);

  // Set up a listener for all history events to determine the CURRENT status
  useEffect(() => {
    const historyCollectionRef = collection(db, 'cleaning_history');
    const q = query(historyCollectionRef, orderBy('timestamp', 'asc'));
    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const eventMap = new Map();
      querySnapshot.forEach((doc) => {
        eventMap.set(doc.data().taskId, doc.data());
      });
      setLastEvents(Object.fromEntries(eventMap.entries()));
    });
    return () => unsubscribe();
  }, []);

  const handleLogEvent = async (itemId) => {
    if (!user) return console.error("User not authenticated");
    await addDoc(collection(db, 'cleaning_history'), {
      taskId: itemId,
      action: 'done',
      userId: user.uid,
      userEmail: user.email || 'Utilisateur inconnu',
      timestamp: Timestamp.now(),
    });
  };

  const handleFrequencyChange = async (taskId, newFrequencyMinutes) => {
    try {
      const taskDocRef = firestoreDoc(db, 'cleaning_tasks', taskId);
      await updateDoc(taskDocRef, { frequency: newFrequencyMinutes * 60000 }); // Convert min to ms
      alert(`Fréquence de ${taskId} mise à jour à ${newFrequencyMinutes} minutes.`);
    } catch (error) {
      console.error("Erreur lors de la mise à jour de la fréquence:", error);
      alert("Erreur lors de la mise à jour de la fréquence.");
    }
  };

  const handleAddItem = async () => {
    if (!newItemName || !newItemCategory || newItemFrequencyMinutes <= 0) {
      alert("Veuillez remplir tous les champs et la fréquence doit être supérieure à 0.");
      return;
    }
    setIsAddingItem(true);
    try {
      const tasksCollectionRef = collection(db, 'cleaning_tasks');
      const newDocRef = firestoreDoc(tasksCollectionRef); // Let Firestore generate unique ID
      await firestoreDoc(tasksCollectionRef, newDocRef.id).set({ // Use set with generated ID
        id: newDocRef.id, // Store the ID in the document itself
        name: newItemName,
        category: newItemCategory === "Nouvelle Catégorie" ? newItemName : newItemCategory, // If 'Nouvelle Catégorie' selected, use item name
        frequency: newItemFrequencyMinutes * 60000, // Convert minutes to ms
      });
      alert(`Nouvelle tâche "${newItemName}" ajoutée à la catégorie "${newItemCategory}".`);
      setNewItemName('');
      setNewItemFrequencyMinutes(60);
      setNewItemCategory('');
      setShowAddItemForm(false);
    } catch (error) {
      console.error("Erreur lors de l'ajout de la tâche:", error);
      alert("Erreur lors de l'ajout de la tâche.");
    } finally {
      setIsAddingItem(false);
    }
  };

  const handleShowHistory = (task) => setModalTask(task);
  const handleCloseModal = () => setModalTask(null);

  const allCategories = Object.keys(taskConfig);

  return (
    <div className="p-4 sm:p-6 text-white max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-yellow-500 mb-6 text-center">Checklist de Nettoyage</h1>

      {isAdmin && (
        <div className="mb-6">
          <button 
            onClick={() => setShowAddItemForm(!showAddItemForm)}
            className="px-4 py-2 bg-blue-600/80 text-white rounded-lg hover:bg-blue-500 transition-colors flex items-center gap-2"
          >
            <PlusCircle size={20} />
            {showAddItemForm ? 'Annuler l\'ajout de tâche' : 'Ajouter une nouvelle tâche'}
          </button>

          {showAddItemForm && (
            <div className="mt-4 p-4 bg-gray-800 rounded-lg space-y-3">
              <h3 className="text-xl font-semibold text-yellow-500">Nouvelle Tâche</h3>
              <div>
                <label className="block text-sm text-gray-400 mb-1">Nom de la tâche</label>
                <input
                  type="text"
                  value={newItemName}
                  onChange={(e) => setNewItemName(e.target.value)}
                  className="w-full bg-black border border-gray-700 rounded p-2 text-white outline-none focus:border-mictlan-gold"
                  placeholder="Ex: Nettoyage tables"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-1">Fréquence (minutes)</label>
                <input
                  type="number"
                  value={newItemFrequencyMinutes}
                  onChange={(e) => setNewItemFrequencyMinutes(parseInt(e.target.value) || 0)}
                  className="w-full bg-black border border-gray-700 rounded p-2 text-white outline-none focus:border-mictlan-gold"
                  min="1"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-1">Catégorie</label>
                <select
                  value={newItemCategory}
                  onChange={(e) => setNewItemCategory(e.target.value)}
                  className="w-full bg-black border border-gray-700 rounded p-2 text-white outline-none focus:border-mictlan-gold"
                >
                  <option value="">-- Sélectionner ou créer une catégorie --</option>
                  {allCategories.map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                  <option value="Nouvelle Catégorie">-- Nouvelle Catégorie --</option>
                </select>
                {newItemCategory === "Nouvelle Catégorie" && (
                  <input
                    type="text"
                    value={newItemCategory === "Nouvelle Catégorie" ? "" : newItemCategory}
                    onChange={(e) => setNewItemCategory(e.target.value)}
                    className="w-full mt-2 bg-black border border-gray-700 rounded p-2 text-white outline-none focus:border-mictlan-gold"
                    placeholder="Nom de la nouvelle catégorie"
                  />
                )}
              </div>
              <button
                onClick={handleAddItem}
                disabled={isAddingItem}
                className="px-4 py-2 bg-green-600/80 text-white rounded-lg hover:bg-green-500 transition-colors"
              >
                {isAddingItem ? 'Ajout en cours...' : 'Sauvegarder la tâche'}
              </button>
            </div>
          )}
        </div>
      )}

      {Object.entries(taskConfig).map(([categoryTitle, tasks]) => (
        <div key={categoryTitle} className="mb-8">
          <h2 className="text-2xl font-semibold border-b-2 border-gray-600 pb-2 mb-4">{categoryTitle}</h2>
          <div className="space-y-3">
            {tasks.map(item => {
              const lastEvent = lastEvents[item.id];
              let isDone = false;
              if (lastEvent && lastEvent.action === 'done') {
                const lastDoneTime = lastEvent.timestamp.toDate().getTime();
                if ((now - lastDoneTime) < item.frequency) {
                  isDone = true;
                }
              }
              return (
                <ChecklistItem 
                  key={item.id} 
                  item={item} 
                  onLogEvent={handleLogEvent}
                  onShowHistory={handleShowHistory}
                  isDone={isDone}
                  log={isDone ? lastEvent : null} 
                  isAdmin={isAdmin} // Pass isAdmin prop
                  onFrequencyChange={handleFrequencyChange} // Pass frequency update handler
                />
              );
            })}
          </div>
        </div>
      ))}

      {modalTask && (
        <HistoryModal 
          taskId={modalTask.id} 
          taskName={modalTask.name} 
          onClose={handleCloseModal} 
        />
      )}
    </div>
  );
